import sys

def main():
    # 첫 줄의 콤보 입력 문자열
    s = sys.stdin.readline().strip()
    open_cnt = 0
    ok = True
    for c in s:
        if c == 'A':
            open_cnt += 1
        else:
            open_cnt -= 1
        if open_cnt < 0:
            ok = False
            break
    print("true" if ok and open_cnt == 0 else "false")

if __name__ == "__main__":
    main()

import sys


def main():
    data = sys.stdin.read().split("\n")
    n = int(data[0])
    lost = list(map(int, data[1].split())) if len(data) > 1 and data[1].split() else []
    reserve = list(map(int, data[2].split())) if len(data) > 2 and data[2].split() else []
    cnt = [0] * (n + 2)
    for i in range(1, n + 1):
        cnt[i] = 1
    for r in reserve:
        cnt[r] += 1
    for l in lost:
        cnt[l] -= 1
    # 앞에서부터 그리디하게 빌려준다.
    for i in range(1, n + 1):
        if cnt[i] != 0:
            continue
        if i - 1 >= 1 and cnt[i - 1] == 2:
            cnt[i - 1] -= 1
            cnt[i] += 1
    count = 0
    for i in range(1, n + 1):
        if cnt[i] >= 1:
            count += 1
    print(count)


main()

import sys


def main():
    data = sys.stdin.read().split("\n")
    n = int(data[0])
    parent = list(range(n))

    def find(x):
        # 경로 압축(반복형)
        root = x
        while parent[root] != root:
            root = parent[root]
        while parent[x] != root:
            parent[x], x = root, parent[x]
        return root

    def union(a, b):
        ra, rb = find(a), find(b)
        if ra != rb:
            parent[ra] = rb

    for i in range(n):
        row = list(map(int, data[1 + i].split()))
        for j in range(n):
            if row[j] == 1:
                union(i, j)
    # 루트 개수 = 동맹 세력 수
    count = sum(1 for i in range(n) if find(i) == i)
    print(count)


main()

