import sys


def main():
    data = sys.stdin.read().split("\n")
    n, m = map(int, data[0].split())
    INF = float("inf")
    # 거리 표 초기화. 자기 자신은 0, 나머지는 INF
    d = [[0 if i == j else INF for j in range(n + 1)] for i in range(n + 1)]
    for e in range(m):
        u, v, w = map(int, data[1 + e].split())
        if w < d[u][v]:
            d[u][v] = w
    # 플로이드 워셜
    for k in range(1, n + 1):
        dk = d[k]
        for i in range(1, n + 1):
            dik = d[i][k]
            if dik == INF:
                continue
            di = d[i]
            for j in range(1, n + 1):
                nd = dik + dk[j]
                if nd < di[j]:
                    di[j] = nd
    out = []
    for i in range(1, n + 1):
        row = []
        for j in range(1, n + 1):
            row.append("-1" if d[i][j] == INF else str(d[i][j]))
        out.append(" ".join(row))
    sys.stdout.write("\n".join(out))


main()

import sys


def main():
    data = sys.stdin.read().split("\n")
    n, m, k = map(int, data[0].split())
    seen = set()
    # by[b] = b를 신고한 사람들의 집합
    by = {}
    for i in range(m):
        a, b = map(int, data[1 + i].split())
        key = a * 1000000 + b
        if key not in seen:
            seen.add(key)
            by.setdefault(b, set()).add(a)
    mail = [0] * (n + 1)
    for b, reporters in by.items():
        if len(reporters) >= k:
            for a in reporters:
                mail[a] += 1
    sys.stdout.write(" ".join(str(mail[i]) for i in range(1, n + 1)))


main()

import sys


def main():
    data = sys.stdin.read().split("\n")
    a = data[0]
    b = data[1] if len(data) > 1 else ""
    n, m = len(a), len(b)
    dp = [[0] * (m + 1) for _ in range(n + 1)]
    for i in range(n + 1):
        dp[i][0] = i
    for j in range(m + 1):
        dp[0][j] = j
    # 편집 거리 DP. 같으면 대각선, 다르면 세 연산 중 최소에 1
    for i in range(1, n + 1):
        for j in range(1, m + 1):
            if a[i - 1] == b[j - 1]:
                dp[i][j] = dp[i - 1][j - 1]
            else:
                dp[i][j] = 1 + min(dp[i - 1][j - 1], dp[i - 1][j], dp[i][j - 1])
    sys.stdout.write(str(dp[n][m]))


main()
